const source = (slides, label, classes, body, note) => ({ slides, label, classes, body, note });

const numbered = (items) => `<div class="number-grid">${items.map((item, index) => `<article class="numbered"><div class="n">${String(index + 1).padStart(2, '0')}</div><div>${item}</div></article>`).join('')}</div>`;
const chips = (items) => `<div class="chips">${items.map((item) => `<span>${item}</span>`).join('')}</div>`;

